/* Evidence: cmem-worked-cmem-arrays-pointers-bounds-3 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 6522; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_arrays_pointers_bounds_3(const int *values, size_t length, size_t start, size_t count, int *sum) {
  size_t index;
  int total = 0;
  if (values == NULL || sum == NULL || start > length || count > length - start) return 0;
  for (index = start; index < start + count; ++index) total += values[index];
  *sum = total;
  return 1;
}

int main(void) {
  int values[5] = { 5, 6, 7, 8, 9 };
  int sum = 0;
  int rejected = worked_cmem_arrays_pointers_bounds_3(values, 5, 4, 2, &sum);
  int accepted = worked_cmem_arrays_pointers_bounds_3(values, 5, 1, 3, &sum);
  int invariant = !rejected && accepted && sum == 21;
  printf("slice sum=%d invariant=%d\n", sum, invariant);
  return invariant ? 0 : 1;
}

